+// QueryParamDefaults returns the query parameters as `url.Values`, with default values applied
+// for any keys that are missing or have an empty value in the request.
+func (c *Context) QueryParamDefaults(defaults map[string]string) url.Values {
+	params := c.QueryParams()
+	result := make(url.Values, len(params)+len(defaults))
+	for k, v := range params {
+		result[k] = v
+	}
+	for k, v := range defaults {
+		if _, exists := result[k]; !exists {
+			result[k] = []string{v}
+		}
+	}
+	return result
+}
